# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import pickle
import base64
import boto3
from datetime import datetime

def lambda_handler(event, context):
    try:
        body = json.loads(event.get('body', '{}'))
        
        user_action = body.get('user_action', {})
        event_type = body.get('event_type', 'unknown')
        partner_id = body.get('partner_id', 'unknown')
        timestamp = body.get('timestamp', datetime.utcnow().isoformat())
        
        serialized_data = pickle.dumps({
            'user_action': user_action,
            'event_type': event_type,
            'partner_id': partner_id,
            'timestamp': timestamp,
            'metadata': body.get('metadata', {})
        })
        
        encoded_data = base64.b64encode(serialized_data).decode('utf-8')
        
        s3_client = boto3.client('s3')
        bucket_name = 'webhook-events-processed'
        key = f"{partner_id}/{event_type}/{datetime.utcnow().strftime('%Y%m%d%H%M%S')}.pkl"
        
        s3_client.put_object(
            Bucket=bucket_name,
            Key=key,
            Body=serialized_data
        )
        
        sqs_client = boto3.client('sqs')
        queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/webhook-processing-queue'
        
        sqs_client.send_message(
            QueueUrl=queue_url,
            MessageBody=json.dumps({
                'encoded_payload': encoded_data,
                's3_location': f"s3://{bucket_name}/{key}",
                'event_type': event_type,
                'partner_id': partner_id
            })
        )
        
        deserialized_data = pickle.loads(serialized_data)
        
        process_user_action(deserialized_data)
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'status': 'success',
                'message': 'Webhook event processed successfully',
                's3_location': f"s3://{bucket_name}/{key}"
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'status': 'error',
                'message': str(e)
            })
        }

def process_user_action(data):
    dynamodb = boto3.resource('dynamodb')
    table = dynamodb.Table('UserActions')
    
    table.put_item(
        Item={
            'partner_id': data['partner_id'],
            'timestamp': data['timestamp'],
            'event_type': data['event_type'],
            'user_action': str(data['user_action']),
            'metadata': str(data.get('metadata', {}))
        }
    )
    
    if data['event_type'] == 'purchase':
        handle_purchase(data)
    elif data['event_type'] == 'signup':
        handle_signup(data)
    elif data['event_type'] == 'profile_update':
        handle_profile_update(data)

def handle_purchase(data):
    sns_client = boto3.client('sns')
    topic_arn = 'arn:aws:sns:us-east-1:123456789012:purchase-notifications'
    
    sns_client.publish(
        TopicArn=topic_arn,
        Message=json.dumps(data['user_action']),
        Subject=f"Purchase Event from {data['partner_id']}"
    )

def handle_signup(data):
    lambda_client = boto3.client('lambda')
    
    lambda_client.invoke(
        FunctionName='user-onboarding-processor',
        InvocationType='Event',
        Payload=json.dumps(data)
    )

def handle_profile_update(data):
    dynamodb = boto3.resource('dynamodb')
    table = dynamodb.Table('UserProfiles')
    
    user_id = data['user_action'].get('user_id')
    if user_id:
        table.update_item(
            Key={'user_id': user_id},
            UpdateExpression='SET last_updated = :timestamp, partner_id = :partner_id',
            ExpressionAttributeValues={
                ':timestamp': data['timestamp'],
                ':partner_id': data['partner_id']
            }
        )